import 'package:flutter/material.dart';import 'package:provider/provider.dart';import 'package:yunusco_group/launcher_screen.dart';import 'package:yunusco_group/providers/auth_provider.dart';class LoginScreen extends StatefulWidget {  @override  _LoginScreenState createState() => _LoginScreenState();}class _LoginScreenState extends State<LoginScreen> {  final _formKey = GlobalKey<FormState>();  final TextEditingController _nameController = TextEditingController();  final TextEditingController _passwordController = TextEditingController();  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: Colors.white,      body: Center(        child: Padding(          padding: const EdgeInsets.symmetric(horizontal: 24.0),          child: Column(            mainAxisAlignment: MainAxisAlignment.center,            crossAxisAlignment: CrossAxisAlignment.start,            children: [              Text(                "Yunusco System",                style: TextStyle(                  fontSize: 28,                  fontWeight: FontWeight.bold,                  color: Colors.indigo,                ),              ),              SizedBox(height: 20),              Form(                key: _formKey,                child: Column(                  children: [                    TextFormField(                      controller: _nameController,                      decoration: InputDecoration(                        labelText: "Enter Username",                        border: OutlineInputBorder(),                        prefixIcon: Icon(Icons.email, color: Colors.indigo),                      ),                      validator: (value) {                        if (value == null || value.isEmpty) {                          return "Please enter username";                        }                        return null;                      },                    ),                    SizedBox(height: 16),                    TextFormField(                      controller: _passwordController,                      obscureText: true,                      decoration: InputDecoration(                        labelText: "Password",                        border: OutlineInputBorder(),                        prefixIcon: Icon(Icons.lock, color: Colors.indigo),                      ),                      validator: (value) {                        if (value == null || value.isEmpty) {                          return "Please enter your password";                        } else if (value.length < 6) {                          return "Password must be at least 6 characters long";                        }                        return null;                      },                    ),                    SizedBox(height: 20),                    SizedBox(                      width: double.infinity,                      child: Consumer<AuthProvider>(                        builder: (context,provider,_)=>ElevatedButton(                          style: ElevatedButton.styleFrom(                            backgroundColor: Colors.indigo,                            padding: EdgeInsets.symmetric(vertical: 14),                            shape: RoundedRectangleBorder(                              borderRadius: BorderRadius.circular(8),                            ),                          ),                          onPressed: () {                            if (_formKey.currentState!.validate()) {                              provider.login(_nameController.text.trim(), _passwordController.text.trim());                              ScaffoldMessenger.of(context).showSnackBar(                                SnackBar(content: Text("Login Successful")),                              );                            }                          },                          child:provider.isLoading?CircularProgressIndicator(color: Colors.white,): Text(                            "Login",                            style: TextStyle(fontSize: 18, color: Colors.white),                          ),                        ),                      ),                    ),                  ],                ),              ),            ],          ),        ),      ),    );  }}